using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---

var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned metadata for: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// With the default reflection resolver every type resolves, so we use a
// source-gen context that only knows about Person to show both paths.

var limited = new JsonSerializerOptions { TypeInfoResolver = MyContext.Default };

if (limited.TryGetTypeInfo<Person>(out var info))
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded — type: {info!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> returned false");

if (limited.TryGetTypeInfo<Order>(out var orderInfo))
    Console.WriteLine($"TryGetTypeInfo<Order> succeeded — type: {orderInfo!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Order> returned false (Order not in context)");

// --- types & source-gen context ---

public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

[JsonSerializable(typeof(Person))]          // only Person is registered
public partial class MyContext : JsonSerializerContext;

